import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as s,e as a}from"./app-706bfe03.js";const i={},r=a('<h1 id="着色-shading" tabindex="-1"><a class="header-anchor" href="#着色-shading" aria-hidden="true">#</a> 着色( shading )</h1><p>到目前为止，经过 MVP 等一系列变换和光栅化后，理论上我们已经可以得到一张图片了。</p><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3pbza5ygbj20qa0mk75v.jpg" alt="image-20220629191848645" style="zoom:45%;"><p>下一步需要进行着色。</p><p>简单来说，<strong>着色 <em>( shading )</em> 就是计算每个采样像素点的颜色</strong>。如果简单地为一个物体赋予同一个颜色，缺乏明暗效果会使物体没有真实感，如下左图。为此我们需要光照模型来得到右图的结果。</p><img class="img-mid" src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/e6c9d24egy1h3qt0wpw8fj216e0mcaci.jpg" alt="result" style="zoom:35%;"><p>着色也可以认为是<strong>对物体应用材质的过程</strong>，比如石膏球和金属球的材质是不同的，不同材质会对光产生不同的反射或吸收。</p><p><strong>物体的材质和它应用的光照模型是对应的</strong>。</p><p>本章节会介绍：</p><ul><li>泛光模型</li><li><em>Lambert</em> 漫反射模型</li><li><em>Phong</em> 模型</li><li><em>Blinn-Phong</em> 模型</li></ul><p>局部光照模型不是真正准确的模型，其优点是计算快且效果可以接受，它被广泛地运用在各种场景中。后文介绍的光线追踪可以得到更真实的光照效果。</p>',11),o=[r];function m(n,c){return t(),s("div",null,o)}const g=e(i,[["render",m],["__file","3.0着色.html.vue"]]);export{g as default};
